export function nextGeneration(grid: Grid): Grid {
  if (grid.length === 0) return [];
  const live = gridToLiveCells(grid);
  if (live.size === 0) return [];

  const candidates = new Set<string>();
  for (const key of live) {
    candidates.add(key);
    const [r, c] = parseKey(key);
    for (const [nr, nc] of getNeighborCoords(r, c)) {
      candidates.add(`${nr},${nc}`);
    }
  }

  const nextLive = new Set<string>();
  for (const key of candidates) {
    const [r, c] = parseKey(key);
    const alive = live.has(key);
    const neighbors = countLiveNeighbors(live, r, c);
    if (willCellLive(alive, neighbors)) {
      nextLive.add(key);
    }
  }

  return liveCellsToGrid(nextLive);
}
```
- Bindings: grid, live, candidates, key, r, c, nr, nc, nextLive, alive, neighbors = 11 x 1 = 11
- Constants: 0, 0 = 2 x 1 = 2
- Invocations: gridToLiveCells(), new Set() x2, candidates.add() x2, parseKey() x2, getNeighborCoords(), countLiveNeighbors(), live.has(), willCellLive(), nextLive.add(), liveCellsToGrid() = 13 x 2 = 26
